// Build the Calendar event payload from visit + lead + property context.
// The event title, description, attendees, and color are all derived so the
// rep's calendar reads like a sales briefing, not a generic appointment.
const body = $('Webhook: Schedule Visit').first().json.body || {};
const visit = $('Supabase: Get Visit').first().json;
const lead = $('Supabase: Get Lead').first().json;
const property = $('Supabase: Get Property').first().json;

// Combine date + time into ISO timestamps (IST = +05:30)
const scheduledDate = body.scheduled_date || visit.scheduled_date;
const scheduledTime = body.scheduled_time || visit.scheduled_time || '10:00';
const durationMinutes = Number(body.duration_minutes || 90);
const tz = 'Asia/Kolkata';

function toIsoIST(date, time) {
  return `${date}T${time}:00+05:30`;
}
function addMinutes(date, time, mins) {
  const d = new Date(toIsoIST(date, time));
  d.setMinutes(d.getMinutes() + mins);
  // Re-render as IST without timezone math drift
  const pad = (n) => String(n).padStart(2, '0');
  const yyyy = d.getFullYear();
  const mm = pad(d.getMonth() + 1);
  const dd = pad(d.getDate());
  const hh = pad(d.getHours());
  const mi = pad(d.getMinutes());
  return `${yyyy}-${mm}-${dd}T${hh}:${mi}:00+05:30`;
}

const startISO = toIsoIST(scheduledDate, scheduledTime);
const endISO = addMinutes(scheduledDate, scheduledTime, durationMinutes);

// Color: hot lead = bold red (id 11), warm = banana (id 5), cold = pale blue (id 9)
let colorId = '9';
if (lead.overall_score >= 80) colorId = '11';
else if (lead.overall_score >= 50) colorId = '5';

const summary = `Site visit · ${property.project_name} · ${lead.name}`;
const description = [
  `Buyer: ${lead.name}  ·  ${lead.phone}${lead.email ? '  ·  ' + lead.email : ''}`,
  `Source: ${lead.source}${lead.matched_property_name ? '  ·  Top match: ' + lead.matched_property_name : ''}`,
  '',
  `Project: ${property.project_name} (${property.developer || 'developer'})`,
  `Locality: ${property.locality}`,
  `Configuration: ${property.config || 'mixed'}`,
  `Price band: ₹${property.price_min_lakhs}-${property.price_max_lakhs} lakhs`,
  '',
  `Buyer's stated intent:`,
  `  · Budget: ${lead.budget_lakhs ? '₹' + lead.budget_lakhs + ' lakhs' : 'not shared'}`,
  `  · Preferred config: ${lead.preferred_config || 'not shared'}`,
  `  · Timeline: ${lead.purchase_timeline || 'not shared'}`,
  `  · Loan status: ${lead.loan_status || 'not shared'}`,
  '',
  `Lead score: ${lead.overall_score || '?'}/100  ·  Confidence: ${lead.confidence || '?'}%`,
  '',
  `Buyer's inquiry text:`,
  `"${(lead.inquiry_text || 'none').slice(0, 400)}"`,
  '',
  `Generated by Pentahouse · trace_id: ${visit.trace_id || 'n/a'}`
].join('\n');

// Calendar event body (Google Calendar API v3)
const attendees = [];
if (body.assigned_rep_email) attendees.push({ email: body.assigned_rep_email, responseStatus: 'accepted' });
const buyerEmail = body.attendee_email || lead.email || null;
if (buyerEmail) attendees.push({ email: buyerEmail, responseStatus: 'needsAction' });

const calendarEventBody = {
  summary,
  description,
  location: property.locality ? `${property.locality}, ${property.city}` : property.city,
  start: { dateTime: startISO, timeZone: tz },
  end:   { dateTime: endISO,   timeZone: tz },
  attendees,
  colorId,
  reminders: { useDefault: false, overrides: [
    { method: 'popup', minutes: 60 },
    { method: 'popup', minutes: 15 }
  ] },
  guestsCanInviteOthers: false,
  guestsCanSeeOtherGuests: false,
  source: { title: 'Pentahouse', url: 'https://pentahouse.in' }
};

return [{ json: { calendarEventBody, scheduledDate, scheduledTime, startISO, endISO, attendees, visit, lead, property } }];

// Extract the Calendar response and prep for the visit row update.
// Even if Calendar errored (neverError=true), we surface the error in the
// payload so the dashboard can show a 'calendar sync failed' banner.
const resp = $('Google Calendar: Create Event').first().json || {};
const ctx = $('Code: Build Calendar Event').first().json;

const ok = !!resp.id && !resp.error;
return [{
  json: {
    ok,
    calendar_event_id: resp.id || null,
    calendar_event_url: resp.htmlLink || null,
    calendar_error: resp.error ? JSON.stringify(resp.error).slice(0, 500) : null,
    visit_id: ctx.visit.id,
    lead_id: ctx.visit.lead_id,
    property_id: ctx.visit.property_id,
    trace_id: ctx.visit.trace_id || null,
    summary: ctx.calendarEventBody.summary,
    startISO: ctx.startISO,
    endISO: ctx.endISO,
    attendees: ctx.attendees
  }
}];
